package main.rice;

/**
 * This class implements a relatively simple algorithm for computing (and printing) the
 * prime factors of a number.  At initialization, a list of primes is computed. Given a
 * number, this list is used to efficiently compute the prime factors of that number.
 */
public class PrimeFactorizer {

    private final int maxNum;
    private final int[] primes;

    public PrimeFactorizer(int maxNumToFactorize) {
        this.maxNum = maxNumToFactorize;

        // Sieve of Eratosthenes up to sqrt(maxNumToFactorize)
        int limit = (int) Math.sqrt(maxNumToFactorize) + 1;
        boolean[] isComposite = new boolean[limit + 1];
        for (int i = 2; (long) i * i <= limit; i++) {
            if (!isComposite[i]) {
                for (int j = i * i; j <= limit; j += i) {
                    isComposite[j] = true;
                }
            }
        }

        // Collect primes
        int count = 0;
        for (int i = 2; i <= limit; i++) {
            if (!isComposite[i]) count++;
        }
        primes = new int[count];
        int idx = 0;
        for (int i = 2; i <= limit; i++) {
            if (!isComposite[i]) primes[idx++] = i;
        }
    }

    public int[] computePrimeFactorization(int numToFactorize) {
        if (numToFactorize <= 1 || numToFactorize > maxNum) {
            return null;
        }

        // First pass: count factors
        int n = numToFactorize;
        int factorCount = 0;
        for (int prime : primes) {
            while (n % prime == 0) {
                factorCount++;
                n /= prime;
            }
            if (n == 1) break;
        }
        if (n > 1) factorCount++; // remaining prime factor

        // Second pass: fill array
        int[] factors = new int[factorCount];
        n = numToFactorize;
        int idx = 0;
        for (int prime : primes) {
            while (n % prime == 0) {
                factors[idx++] = prime;
                n /= prime;
            }
            if (n == 1) break;
        }
        if (n > 1) factors[idx] = n;

        return factors;
    }
}

